class Solution:
    def sumAndMultiply(self, n):
        digits = []
        if n == 0:
            digits = [0]
        else:
            temp = n
            while temp > 0:
                digits.append(temp % 10)
                temp //= 10
            digits.reverse()
        nz = [d for d in digits if d != 0]
        if not nz:
            x = 0
        else:
            x = 0
            for d in nz:
                x = x * 10 + d
        if x == 0:
            s = 0
        else:
            t = x
            s = 0
            while t > 0:
                s += t % 10
                t //= 10
        return x * s

