var sumAndMultiply = function(n) {
    const s = String(n);
    const nz = [...s].filter(c => c !== '0');
    const x = nz.length ? parseInt(nz.join(''), 10) : 0;
    const digitSum = [...String(x)].reduce((acc, c) => acc + Number(c), 0);
    return x * digitSum;
};
